import { Component, For, JSX } from 'solid-js';

export interface TextRotateProps {
  class?: { root?: string; item?: string };
  items?: TextRotateItem[];
}
type TextRotateItem = string | (() => JSX.Element);

export const TextRotate: Component<TextRotateProps> = p => {
  if (p.items?.length === 0 || p.items === undefined) {
    console.warn('TextRotate: No items provided');
    return <></>;
  } else if (p.items?.length > 6) {
    console.warn('TextRotate: More than 6 items may cause performance issues');
    return <></>;
  }
  return (
    <span class={p.class?.root ?? 'text-rotate'}>
      <span>
        <For each={p.items}>
          {item =>
            typeof item === 'function' ? item() : <span class={p.class?.item}>{item}</span>
          }
        </For>
      </span>
    </span>
  );
};
